import React, { useState, useEffect } from 'react';
import { 
  LayoutDashboard, Package, Users, DollarSign, TrendingUp, 
  Plus, X, Search, ShoppingCart, LogOut, Check, Clock 
} from 'lucide-react';
import { partnerService } from '../services/api';

function PartnerDashboard({ user, onLogout }) {
  const [activeTab, setActiveTab] = useState('dashboard');
  const [dashboard, setDashboard] = useState(null);
  const [products, setProducts] = useState([]);
  const [buyers, setBuyers] = useState([]);
  const [sales, setSales] = useState([]);
  const [loading, setLoading] = useState(true);
  const [showSaleModal, setShowSaleModal] = useState(false);
  const [selectedProduct, setSelectedProduct] = useState(null);
  const [buyerSearch, setBuyerSearch] = useState('');
  const [searchResults, setSearchResults] = useState([]);
  const [selectedBuyer, setSelectedBuyer] = useState(null);
  const [saleNotes, setSaleNotes] = useState('');

  useEffect(() => {
    loadData();
  }, [activeTab]);

  const loadData = async () => {
    setLoading(true);
    try {
      if (activeTab === 'dashboard') {
        const response = await partnerService.getDashboard();
        setDashboard(response.data);
      } else if (activeTab === 'products') {
        const response = await partnerService.getProducts();
        setProducts(response.data);
      } else if (activeTab === 'buyers') {
        const response = await partnerService.getBuyers();
        setBuyers(response.data);
      } else if (activeTab === 'sales') {
        const response = await partnerService.getSales();
        setSales(response.data);
      }
    } catch (error) {
      console.error('Error loading data:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleCreateSale = (product) => {
    setSelectedProduct(product);
    setSelectedBuyer(null);
    setBuyerSearch('');
    setSearchResults([]);
    setSaleNotes('');
    setShowSaleModal(true);
  };

  const handleBuyerSearch = async (email) => {
    setBuyerSearch(email);
    if (email.length >= 3) {
      try {
        const response = await partnerService.searchBuyers(email);
        setSearchResults(response.data);
      } catch (error) {
        console.error('Error searching buyers:', error);
      }
    } else {
      setSearchResults([]);
    }
  };

  const handleSelectBuyer = async (buyer) => {
    setSelectedBuyer(buyer);
    setSearchResults([]);

    // Check if buyer can purchase this product
    try {
      const response = await partnerService.canSellToBuyer(
        selectedProduct.productId,
        buyer.userId
      );
      if (!response.data.canSell) {
        alert('This buyer has already purchased this product from another partner.');
        setSelectedBuyer(null);
      }
    } catch (error) {
      alert('Error checking buyer eligibility');
      setSelectedBuyer(null);
    }
  };

  const handleSaleSubmit = async (e) => {
    e.preventDefault();
    if (!selectedProduct || !selectedBuyer) return;

    try {
      await partnerService.createSale({
        productId: selectedProduct.productId,
        buyerId: selectedBuyer.userId,
        notes: saleNotes,
      });
      setShowSaleModal(false);
      loadData();
      alert('Sale created successfully!');
    } catch (error) {
      alert(error.response?.data?.message || 'Error creating sale');
    }
  };

  const formatCurrency = (amount) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
    }).format(amount);
  };

  const formatDate = (dateString) => {
    return new Date(dateString).toLocaleDateString('en-US', {
      year: 'numeric',
      month: 'short',
      day: 'numeric',
    });
  };

  const getStatusBadge = (status) => {
    const badges = {
      Completed: 'badge-success',
      Pending: 'badge-warning',
      Failed: 'badge-danger',
    };
    return badges[status] || 'badge-primary';
  };

  const calculateCommission = (price, percentage) => {
    return price * (percentage / 100);
  };

  return (
    <div className="dashboard">
      <div className="sidebar">
        <div className="sidebar-logo">
          <h2>Sales ERP</h2>
          <p>Partner Panel</p>
        </div>

        <div className="sidebar-menu">
          <div
            className={`menu-item ${activeTab === 'dashboard' ? 'active' : ''}`}
            onClick={() => setActiveTab('dashboard')}
          >
            <LayoutDashboard size={20} />
            Dashboard
          </div>
          <div
            className={`menu-item ${activeTab === 'products' ? 'active' : ''}`}
            onClick={() => setActiveTab('products')}
          >
            <Package size={20} />
            Products
          </div>
          <div
            className={`menu-item ${activeTab === 'buyers' ? 'active' : ''}`}
            onClick={() => setActiveTab('buyers')}
          >
            <Users size={20} />
            My Buyers
          </div>
          <div
            className={`menu-item ${activeTab === 'sales' ? 'active' : ''}`}
            onClick={() => setActiveTab('sales')}
          >
            <DollarSign size={20} />
            Sales History
          </div>
        </div>

        <div className="sidebar-footer">
          <div className="user-info">
            <p>{user.fullName}</p>
            <span>{user.email}</span>
          </div>
          <button className="btn btn-secondary" style={{ width: '100%' }} onClick={onLogout}>
            <LogOut size={16} />
            Logout
          </button>
        </div>
      </div>

      <div className="main-content">
        {activeTab === 'dashboard' && dashboard && (
          <>
            <div className="page-header">
              <h1>Dashboard</h1>
              <p>Welcome back, {user.fullName}!</p>
            </div>

            <div className="stats-grid">
              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon primary">
                    <ShoppingCart size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Sales</h3>
                  <p>{dashboard.stats.totalSales}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon success">
                    <DollarSign size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Revenue</h3>
                  <p>{formatCurrency(dashboard.stats.totalRevenue)}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon warning">
                    <TrendingUp size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Total Commission</h3>
                  <p>{formatCurrency(dashboard.stats.totalCommission)}</p>
                </div>
              </div>

              <div className="stat-card">
                <div className="stat-header">
                  <div className="stat-icon success">
                    <Check size={24} />
                  </div>
                </div>
                <div className="stat-content">
                  <h3>Paid Commission</h3>
                  <p>{formatCurrency(dashboard.stats.paidCommission)}</p>
                </div>
              </div>
            </div>

            <div className="card">
              <div className="card-header">
                <h2>Recent Sales</h2>
              </div>
              <div className="table-container">
                {dashboard.recentSales.length === 0 ? (
                  <div className="empty-state">
                    <ShoppingCart size={64} />
                    <h3>No sales yet</h3>
                    <p>Start selling products to see your sales here</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>Product</th>
                        <th>Buyer</th>
                        <th>Company</th>
                        <th>Amount</th>
                        <th>Commission</th>
                        <th>Date</th>
                        <th>Status</th>
                      </tr>
                    </thead>
                    <tbody>
                      {dashboard.recentSales.map((sale) => (
                        <tr key={sale.saleId}>
                          <td><strong>{sale.productName}</strong></td>
                          <td>{sale.buyerName}</td>
                          <td>{sale.buyerCompany || 'N/A'}</td>
                          <td>{formatCurrency(sale.saleAmount)}</td>
                          <td>{formatCurrency(sale.commissionAmount)}</td>
                          <td>{formatDate(sale.saleDate)}</td>
                          <td>
                            <span className={`badge ${getStatusBadge(sale.paymentStatus)}`}>
                              {sale.paymentStatus}
                            </span>
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>

            <div className="card">
              <div className="card-header">
                <h2>My Buyers ({dashboard.buyers.length})</h2>
              </div>
              <div className="table-container">
                {dashboard.buyers.length === 0 ? (
                  <div className="empty-state">
                    <Users size={64} />
                    <h3>No buyers yet</h3>
                    <p>Your buyers will appear here after first sale</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Company</th>
                        <th>Total Purchases</th>
                        <th>Total Spent</th>
                        <th>Last Purchase</th>
                      </tr>
                    </thead>
                    <tbody>
                      {dashboard.buyers.map((buyer) => (
                        <tr key={buyer.userId}>
                          <td><strong>{buyer.fullName}</strong></td>
                          <td>{buyer.email}</td>
                          <td>{buyer.companyName || 'N/A'}</td>
                          <td>{buyer.totalPurchases}</td>
                          <td>{formatCurrency(buyer.totalSpent)}</td>
                          <td>{formatDate(buyer.lastPurchase)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>
          </>
        )}

        {activeTab === 'products' && (
          <>
            <div className="page-header">
              <h1>Available Products</h1>
              <p>Browse and sell products to your clients</p>
            </div>

            {loading ? (
              <div style={{ textAlign: 'center', padding: '48px' }}>Loading...</div>
            ) : (
              <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fill, minmax(350px, 1fr))', gap: '24px' }}>
                {products.map((product) => (
                  <div key={product.productId} className="card">
                    <h3 style={{ marginBottom: '12px', fontSize: '20px' }}>{product.productName}</h3>
                    <p style={{ color: 'var(--text-secondary)', marginBottom: '16px', minHeight: '60px' }}>
                      {product.description}
                    </p>
                    <div style={{ marginBottom: '16px' }}>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                        <span style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>Price:</span>
                        <strong style={{ fontSize: '18px' }}>{formatCurrency(product.price)}</strong>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                        <span style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>Commission:</span>
                        <strong style={{ color: 'var(--secondary-color)' }}>
                          {product.commissionPercentage}% ({formatCurrency(calculateCommission(product.price, product.commissionPercentage))})
                        </strong>
                      </div>
                      <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                        <span style={{ color: 'var(--text-secondary)', fontSize: '14px' }}>Provider:</span>
                        <span>{product.adminName}</span>
                      </div>
                    </div>
                    <button 
                      className="btn btn-primary" 
                      style={{ width: '100%' }}
                      onClick={() => handleCreateSale(product)}
                    >
                      <Plus size={16} />
                      Create Sale
                    </button>
                  </div>
                ))}
              </div>
            )}
          </>
        )}

        {activeTab === 'buyers' && (
          <>
            <div className="page-header">
              <h1>My Buyers</h1>
              <p>View all your buyers and their purchase history</p>
            </div>

            <div className="card">
              <div className="table-container">
                {loading ? (
                  <div style={{ textAlign: 'center', padding: '48px' }}>Loading...</div>
                ) : buyers.length === 0 ? (
                  <div className="empty-state">
                    <Users size={64} />
                    <h3>No buyers yet</h3>
                    <p>Start selling products to build your buyer base</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>Name</th>
                        <th>Email</th>
                        <th>Company</th>
                        <th>Phone</th>
                        <th>Total Purchases</th>
                        <th>Total Spent</th>
                        <th>Last Purchase</th>
                      </tr>
                    </thead>
                    <tbody>
                      {buyers.map((buyer) => (
                        <tr key={buyer.userId}>
                          <td><strong>{buyer.fullName}</strong></td>
                          <td>{buyer.email}</td>
                          <td>{buyer.companyName || 'N/A'}</td>
                          <td>{buyer.phoneNumber || 'N/A'}</td>
                          <td>{buyer.totalPurchases}</td>
                          <td>{formatCurrency(buyer.totalSpent)}</td>
                          <td>{formatDate(buyer.lastPurchase)}</td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>
          </>
        )}

        {activeTab === 'sales' && (
          <>
            <div className="page-header">
              <h1>Sales History</h1>
              <p>View all your completed and pending sales</p>
            </div>

            <div className="card">
              <div className="table-container">
                {loading ? (
                  <div style={{ textAlign: 'center', padding: '48px' }}>Loading...</div>
                ) : sales.length === 0 ? (
                  <div className="empty-state">
                    <DollarSign size={64} />
                    <h3>No sales yet</h3>
                    <p>Your sales history will appear here</p>
                  </div>
                ) : (
                  <table>
                    <thead>
                      <tr>
                        <th>ID</th>
                        <th>Product</th>
                        <th>Buyer</th>
                        <th>Company</th>
                        <th>Amount</th>
                        <th>Commission</th>
                        <th>Date</th>
                        <th>Status</th>
                        <th>License Key</th>
                      </tr>
                    </thead>
                    <tbody>
                      {sales.map((sale) => (
                        <tr key={sale.saleId}>
                          <td>#{sale.saleId}</td>
                          <td><strong>{sale.productName}</strong></td>
                          <td>{sale.buyerName}</td>
                          <td>{sale.buyerCompany || 'N/A'}</td>
                          <td>{formatCurrency(sale.saleAmount)}</td>
                          <td>{formatCurrency(sale.commissionAmount)}</td>
                          <td>{formatDate(sale.saleDate)}</td>
                          <td>
                            <span className={`badge ${getStatusBadge(sale.paymentStatus)}`}>
                              {sale.paymentStatus}
                            </span>
                          </td>
                          <td style={{ fontFamily: 'monospace', fontSize: '12px' }}>
                            {sale.licenseKey}
                          </td>
                        </tr>
                      ))}
                    </tbody>
                  </table>
                )}
              </div>
            </div>
          </>
        )}
      </div>

      {showSaleModal && selectedProduct && (
        <div className="modal-overlay" onClick={() => setShowSaleModal(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>
            <div className="modal-header">
              <h2>Create Sale - {selectedProduct.productName}</h2>
              <button className="modal-close" onClick={() => setShowSaleModal(false)}>
                <X size={20} />
              </button>
            </div>

            <div style={{ marginBottom: '24px', padding: '16px', background: 'var(--bg-secondary)', borderRadius: '8px' }}>
              <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '8px' }}>
                <span>Product Price:</span>
                <strong>{formatCurrency(selectedProduct.price)}</strong>
              </div>
              <div style={{ display: 'flex', justifyContent: 'space-between' }}>
                <span>Your Commission ({selectedProduct.commissionPercentage}%):</span>
                <strong style={{ color: 'var(--secondary-color)' }}>
                  {formatCurrency(calculateCommission(selectedProduct.price, selectedProduct.commissionPercentage))}
                </strong>
              </div>
            </div>

            <form onSubmit={handleSaleSubmit}>
              <div className="form-group">
                <label>Search Buyer by Email *</label>
                <div style={{ position: 'relative' }}>
                  <input
                    type="text"
                    value={buyerSearch}
                    onChange={(e) => handleBuyerSearch(e.target.value)}
                    placeholder="Type buyer's email..."
                    style={{ paddingLeft: '40px' }}
                  />
                  <Search 
                    size={16} 
                    style={{ 
                      position: 'absolute', 
                      left: '12px', 
                      top: '50%', 
                      transform: 'translateY(-50%)',
                      color: 'var(--text-tertiary)'
                    }} 
                  />
                </div>

                {searchResults.length > 0 && (
                  <div style={{
                    border: '1px solid var(--border-color)',
                    borderRadius: '8px',
                    marginTop: '8px',
                    maxHeight: '200px',
                    overflowY: 'auto'
                  }}>
                    {searchResults.map((buyer) => (
                      <div
                        key={buyer.userId}
                        onClick={() => handleSelectBuyer(buyer)}
                        style={{
                          padding: '12px',
                          cursor: 'pointer',
                          borderBottom: '1px solid var(--border-color)',
                          transition: 'background 0.2s'
                        }}
                        onMouseEnter={(e) => e.target.style.background = 'var(--bg-secondary)'}
                        onMouseLeave={(e) => e.target.style.background = 'transparent'}
                      >
                        <div style={{ fontWeight: '600' }}>{buyer.fullName}</div>
                        <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>
                          {buyer.email} {buyer.companyName && `• ${buyer.companyName}`}
                        </div>
                      </div>
                    ))}
                  </div>
                )}

                {selectedBuyer && (
                  <div style={{
                    marginTop: '12px',
                    padding: '12px',
                    background: 'var(--bg-secondary)',
                    borderRadius: '8px'
                  }}>
                    <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center' }}>
                      <div>
                        <div style={{ fontWeight: '600' }}>{selectedBuyer.fullName}</div>
                        <div style={{ fontSize: '12px', color: 'var(--text-secondary)' }}>
                          {selectedBuyer.email}
                        </div>
                      </div>
                      <button
                        type="button"
                        onClick={() => setSelectedBuyer(null)}
                        style={{
                          background: 'none',
                          border: 'none',
                          cursor: 'pointer',
                          padding: '4px',
                          color: 'var(--danger-color)'
                        }}
                      >
                        <X size={16} />
                      </button>
                    </div>
                  </div>
                )}
              </div>

              <div className="form-group">
                <label>Notes (Optional)</label>
                <textarea
                  value={saleNotes}
                  onChange={(e) => setSaleNotes(e.target.value)}
                  rows="3"
                  placeholder="Add any notes about this sale..."
                />
              </div>

              <div className="modal-footer">
                <button 
                  type="button" 
                  className="btn btn-secondary" 
                  onClick={() => setShowSaleModal(false)}
                >
                  Cancel
                </button>
                <button 
                  type="submit" 
                  className="btn btn-primary"
                  disabled={!selectedBuyer}
                >
                  Create Sale
                </button>
              </div>
            </form>
          </div>
        </div>
      )}
    </div>
  );
}

export default PartnerDashboard;
